import fs from 'fs';
import path from 'path';
import readline from 'readline';
import { Agent, LocalAgentConfig } from '@google/antigravity';

function getLocalDirectorySize(args) {
  const { dirPath } = args;
  try {
    const resolvedPath = path.resolve(dirPath);
    if (!fs.existsSync(resolvedPath)) {
      return "Path does not exist.";
    }
    const files = fs.readdirSync(resolvedPath);
    return `Directory '${resolvedPath}' contains ${files.length} items.`;
  } catch (err) {
    return err.message;
  }
}

function promptUser(query) {
  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
  });
  return new Promise(resolve => rl.question(query, answer => {
    rl.close();
    resolve(answer);
  }));
}

async function runPersistenceAndGate() {
  const baseDir = path.resolve("./workspace_sessions");
  const saveDir = path.join(baseDir, "saves");
  const appDataDir = path.join(baseDir, "brain");

  if (!fs.existsSync(saveDir)) fs.mkdirSync(saveDir, { recursive: true });
  if (!fs.existsSync(appDataDir)) fs.mkdirSync(appDataDir, { recursive: true });

  const tools = [{
    name: 'getLocalDirectorySize',
    description: 'Calculates total files and folder count inside a local directory path.',
    parameters: {
      type: 'object',
      properties: {
        dirPath: { type: 'string' }
      },
      required: ['dirPath']
    },
    execute: getLocalDirectorySize
  }];

  const hooks = {
    preToolCallDecide: async (toolCall) => {
      console.log(`\n[SECURITY GATE] Node Agent requested tool: ${toolCall.name}`);
      console.log(`[SECURITY GATE] Arguments:`, toolCall.args);
      const answer = await promptUser("Approve tool execution? (y/n): ");
      if (answer.trim().toLowerCase() === 'y') {
        return { allow: true };
      }
      return { allow: false };
    }
  };

  console.log("--- Starting Session 1 ---");
  const config1 = new LocalAgentConfig({
    saveDir,
    appDataDir,
    tools,
    hooks
  });

  const agent1 = new Agent(config1);
  await agent1.start();

  let sessionId;
  try {
    const response = await agent1.chat("Check the size of the current directory '.' using the getLocalDirectorySize tool.");
    console.log(`Response:`, await response.text());
    sessionId = agent1.conversationId;
    console.log(`Session ID Saved: ${sessionId}`);
  } finally {
    await agent1.stop();
  }

  console.log("\n--- Starting Session 2 (Resumed) ---");
  const config2 = new LocalAgentConfig({
    conversationId: sessionId,
    saveDir,
    appDataDir,
    tools,
    hooks
  });

  const agent2 = new Agent(config2);
  await agent2.start();
  try {
    const response = await agent2.chat("Confirm what tool you used in the previous step and summarize its output.");
    console.log(`Resumed Response:`, await response.text());
  } finally {
    await agent2.stop();
  }
}

runPersistenceAndGate().catch(console.error);
